// // This module selects the input based on the 2-bit select signal 'sel'. When 'sel' is 0, the output 'Y' takes the value of D; when 'sel' is 1, it becomes C; when 'sel' is 2, it becomes B; and when 'sel' is 3, it becomes A. If 'sel' takes any other value, the output 'Y' is set to an unknown state represented by 1'bx.
module top_module(A, B, C, D, sel, Y);input A, B, C, D;
input [1:0] sel;
output reg Y;

always @ (sel or A or B or C or D)
begin

	if (sel == 0)
		Y <= A;
	else
	begin
		if (sel == 1)
			Y <= B;
		else
		begin
			if (sel == 2)
				Y <= C;
			else
			begin
				if (sel == 3)
					Y <= D;
				else
					Y <= 1'bx;
			end
		end
	end
end

endmodule
